    24→const DEFAULT_PROFILE_LAYOUT = {
    25→    version: 1,
    26→    preset: 'classic',
    27→    spacing: 'md',
    28→    radius: 'lg',
    29→    sections: [
    30→        {id: 'stats', visible: true, size: 'md', x: 24, y: 16},
    31→        {id: 'bio', visible: true, size: 'md', x: 24, y: 108},
    32→        {id: 'joined_date', visible: true, size: 'md', x: 24, y: 196},
    33→    ]
    34→};
    35→const PROFILE_SECTION_LABELS = {
    36→    stats: 'Stats',
    37→    bio: 'Bio',
    38→    joined_date: 'Joined date'
    39→};
    40→const PROFILE_SECTION_CODES = {
    41→    stats: 'ST',
    42→    bio: 'BIO',
    43→    joined_date: 'JD'
    44→};
    45→const PROFILE_SECTION_IDS = Object.keys(PROFILE_SECTION_LABELS);
    46→const PROFILE_SECTION_SIZES = ['sm', 'md', 'lg'];
    47→const PROFILE_WIDGET_TYPES = ['note', 'photo_note'];
    48→const PROFILE_WIDGET_SIZES = ['sm', 'md', 'lg'];
    49→const PROFILE_WIDGET_GRID_SIZE = 24;
    50→const PROFILE_SECTION_GRID_SIZE = 24;
    51→
    52→const getDefaultSectionPosition = (sectionId) => {
    53→    if(sectionId === 'stats'){
    54→        return {x: 24, y: 16};
    55→    }
    56→    if(sectionId === 'bio'){
    57→        return {x: 24, y: 108};
    58→    }
    59→    return {x: 24, y: 196};
    60→};
    61→
    62→const getDefaultWidgetPosition = (index = 0) => ({
    63→    x: 24 + ((index % 2) * 240),
    64→    y: 24 + (Math.floor(index / 2) * 144)
    65→});
    66→
    67→const createDefaultWidget = (index = 0) => {
    68→    const defaultPosition = getDefaultWidgetPosition(index);
    69→    return ({
    70→    id: `widget_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    71→    type: 'note',
    72→    size: 'md',
    73→    title: 'New widget',
    74→    note: '',
    75→    image_url: '',
    76→    x: defaultPosition.x,
    77→    y: defaultPosition.y,
    78→    height: null,
    79→    image_width: null,
    80→    image_height: null,
    81→    pinned_section: null
    82→});
    83→};
    84→
    85→const normalizeProfileLayout = (layout) => {
    86→    const normalized = {
    87→        version: layout?.version || DEFAULT_PROFILE_LAYOUT.version,
    88→        preset: layout?.preset || DEFAULT_PROFILE_LAYOUT.preset,
    89→        spacing: layout?.spacing || DEFAULT_PROFILE_LAYOUT.spacing,
    90→        radius: layout?.radius || DEFAULT_PROFILE_LAYOUT.radius,
    91→        sections: DEFAULT_PROFILE_LAYOUT.sections.map((section) => ({...section})),
    92→        widgets: []
    93→    };
    94→
    95→    const incomingSections = Array.isArray(layout?.sections) ? layout.sections : [];
    96→    const normalizedSections = [];
    97→
    98→    incomingSections.forEach((section) => {
    99→        if(!PROFILE_SECTION_IDS.includes(section?.id)){
   100→            return;
   101→        }
   102→        if(normalizedSections.find((item) => item.id === section.id)){
   103→            return;
   104→        }
   105→
   106→        normalizedSections.push({
   107→            id: section.id,
   108→            visible: true,
   109→            size: PROFILE_SECTION_SIZES.includes(section?.size) ? section.size : 'md',
   110→            x: Number.isFinite(section?.x) ? Math.max(0, section.x) : getDefaultSectionPosition(section.id).x,
   111→            y: Number.isFinite(section?.y) ? Math.max(0, section.y) : getDefaultSectionPosition(section.id).y,
   112→            height: Number.isFinite(section?.height) ? Math.max(72, section.height) : null,
   113→            content_width: Number.isFinite(section?.content_width) ? Math.max(120, section.content_width) : null,
   114→            content_height: Number.isFinite(section?.content_height) ? Math.max(40, section.content_height) : null
   115→        });
   116→    });
   117→
   118→    PROFILE_SECTION_IDS.forEach((sectionId) => {
   119→        if(normalizedSections.find((section) => section.id === sectionId)){
   120→            return;
   121→        }
   122→
   123→        const defaultSection = DEFAULT_PROFILE_LAYOUT.sections.find((section) => section.id === sectionId);
   124→        normalizedSections.push({...defaultSection});
   125→    });
   126→
   127→    normalized.sections = normalizedSections;
   128→
   129→    const incomingWidgets = Array.isArray(layout?.widgets) ? layout.widgets : [];
   130→    normalized.widgets = incomingWidgets
   131→        .filter((widget) => widget && typeof widget === 'object')
   132→        .map((widget) => ({
   133→            id: widget.id || `widget_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
   134→            type: PROFILE_WIDGET_TYPES.includes(widget.type) ? widget.type : 'note',
   135→            size: PROFILE_WIDGET_SIZES.includes(widget.size) ? widget.size : 'md',
   136→            title: typeof widget.title === 'string' ? widget.title : '',
   137→            note: typeof widget.note === 'string' ? widget.note : '',
   138→            image_url: typeof widget.image_url === 'string' ? widget.image_url : '',
   139→            x: Number.isFinite(widget?.x) ? Math.max(0, widget.x) : 24,
   140→            y: Number.isFinite(widget?.y) ? Math.max(0, widget.y) : 24,
   141→            height: Number.isFinite(widget?.height) ? Math.max(96, widget.height) : null,
   142→            image_width: Number.isFinite(widget?.image_width) ? Math.max(60, widget.image_width) : null,
   143→            image_height: Number.isFinite(widget?.image_height) ? Math.max(40, widget.image_height) : null,
   144→            pinned_section: PROFILE_SECTION_IDS.includes(widget?.pinned_section) ? widget.pinned_section : null
   145→        }));
   146→
   147→    return normalized;
   148→};
