## 3. New Handler Functions

All handlers follow the existing patterns found in the codebase. Each one is detailed below.

### 3a. Block CRUD Helpers

```js
const createDefaultBlock = (type = 'text', index = 0) => ({
    id: `block_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    type,
    content: type === 'text' ? 'Text' : '',
    title: type === 'image' ? '' : undefined,
    note: type === 'image' ? '' : undefined,
    image_url: type === 'image' ? '' : undefined,
    bg_color: null,
    x: 8 + ((index % 2) * 100),
    y: 8 + (Math.floor(index / 2) * 60),
    width: type === 'text' ? 160 : 200,
    height: type === 'text' ? 40 : 140,
    image_width: null,
    image_height: null
});

const handleAddBlock = (widgetId, blockType = 'text') => {
    setProfileLayoutDraft((prev) => ({
        ...prev,
        widgets: prev.widgets.map((widget) => {
            if (widget.id !== widgetId) return widget;
            const blocks = Array.isArray(widget.blocks) ? widget.blocks : [];
            return {
                ...widget,
                blocks: [...blocks, createDefaultBlock(blockType, blocks.length)]
            };
        })
    }));
    triggerAutoSave();
};

const handleRemoveBlock = (widgetId, blockId) => {
    setProfileLayoutDraft((prev) => ({
        ...prev,
        widgets: prev.widgets.map((widget) => {
            if (widget.id !== widgetId) return widget;
            return {
                ...widget,
                blocks: (widget.blocks || []).filter((b) => b.id !== blockId)
            };
        })
    }));
    setSelectedBlockId((prev) => prev === blockId ? null : prev);
    triggerAutoSave();
};

const handleBlockFieldChange = (widgetId, blockId, field, value) => {
    setProfileLayoutDraft((prev) => ({
        ...prev,
        widgets: prev.widgets.map((widget) => {
            if (widget.id !== widgetId) return widget;
            return {
                ...widget,
                blocks: (widget.blocks || []).map((block) =>
                    block.id === blockId ? { ...block, [field]: value } : block
                )
            };
        })
    }));
};
```

### 3b. Block Drag Handler (mirrors `widgetMoveState` pattern at lines 565-577 and 962-1039)

```js
const handleStartBlockDrag = (e, widgetId, blockId) => {
    e.preventDefault();
    e.stopPropagation();
    const widget = profileLayoutDraft.widgets.find((w) => w.id === widgetId);
    const block = (widget?.blocks || []).find((b) => b.id === blockId);
    if (!block) return;

    setBlockDragState({
        widgetId,
        blockId,
        startX: e.clientX,
        startY: e.clientY,
        originX: Number.isFinite(block.x) ? block.x : 0,
        originY: Number.isFinite(block.y) ? block.y : 0
    });
};
```

### 3c. Block Drag useEffect (mirrors the useEffect at lines 962-1039)

```js
useEffect(() => {
    if (!blockDragState) return;

    let latestEvent = null;
    const handleMouseMove = (e) => {
        latestEvent = e;
        if (blockDragRafRef.current) return;
        blockDragRafRef.current = window.requestAnimationFrame(() => {
            if (!latestEvent) {
                blockDragRafRef.current = null;
                return;
            }
            const rawX = blockDragState.originX + (latestEvent.clientX - blockDragState.startX);
            const rawY = blockDragState.originY + (latestEvent.clientY - blockDragState.startY);
            const snappedX = Math.max(0, Math.round(rawX / 4) * 4); // 4px sub-grid
            const snappedY = Math.max(0, Math.round(rawY / 4) * 4);

            handleBlockFieldChange(blockDragState.widgetId, blockDragState.blockId, 'x', snappedX);
            // Need to update y too -- use a batch update:
            setProfileLayoutDraft((prev) => ({
                ...prev,
                widgets: prev.widgets.map((widget) => {
                    if (widget.id !== blockDragState.widgetId) return widget;
                    return {
                        ...widget,
                        blocks: (widget.blocks || []).map((block) =>
                            block.id === blockDragState.blockId
                                ? { ...block, x: snappedX, y: snappedY }
                                : block
                        )
                    };
                })
            }));
            blockDragRafRef.current = null;
        });
    };

    const handleMouseUp = () => {
        if (blockDragRafRef.current) {
            window.cancelAnimationFrame(blockDragRafRef.current);
            blockDragRafRef.current = null;
        }
        setBlockDragState(null);
        triggerAutoSave();
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
    return () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
    };
}, [blockDragState]);
```

